mapper.select:
SELECT r.*, m.member_name AS memberName, m.member_profile_img AS memberProfileImg, m.member_grade AS memberGrade, (SELECT COUNT(*) FROM review_like rl WHERE rl.review_id = r.review_id) AS likeCount, (SELECT COUNT(*) FROM comment c WHERE c.review_id = r.review_id AND c.comment_delete_status != '삭제') AS commentCount FROM review r JOIN member m ON m.member_id = r.member_id
AND (r.review_title LIKE CONCAT('%', #{keyword}, '%') OR m.member_name LIKE CONCAT('%', #{keyword}, '%'))
AND r.review_created_at >= DATE_SUB(NOW(), INTERVAL 1 WEEK) AND r.review_created_at >= DATE_SUB(NOW(), INTERVAL 1 MONTH) AND r.review_created_at >= DATE_SUB(NOW(), INTERVAL 3 MONTH)
AND r.review_highlighted = 'Y'
AND r.review_platform = '넷플릭스' AND r.review_platform = '티빙' AND r.review_platform = '디즈니+' AND r.review_platform = '기타' AND r.review_platform = #{platform}
AND r.review_id IN ( SELECT rm.review_id FROM review_mapping rm WHERE rm.genre_category_id IN
#{gid}
)
ORDER BY likeCount DESC ORDER BY CASE WHEN r.review_highlighted = 'Y' THEN 1 ELSE 0 END DESC, COALESCE(r.review_highlight_started_at, r.review_created_at) ASC ORDER BY r.review_rating DESC ORDER BY r.review_hit DESC ORDER BY r.review_created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM review r JOIN member m ON m.member_id = r.member_id
AND (r.review_title LIKE CONCAT('%', #{keyword}, '%') OR m.member_name LIKE CONCAT('%', #{keyword}, '%'))
AND r.review_created_at >= DATE_SUB(NOW(), INTERVAL 1 WEEK) AND r.review_created_at >= DATE_SUB(NOW(), INTERVAL 1 MONTH) AND r.review_created_at >= DATE_SUB(NOW(), INTERVAL 3 MONTH)
AND r.review_highlighted = 'Y'
AND r.review_platform = '넷플릭스' AND r.review_platform = '티빙' AND r.review_platform = '디즈니+' AND r.review_platform = '기타' AND r.review_platform = #{platform}
AND r.review_id IN ( SELECT rm.review_id FROM review_mapping rm WHERE rm.genre_category_id IN
#{gid}
)

SELECT r.*, m.member_name AS memberName, m.member_profile_img AS memberProfileImg, m.member_grade AS memberGrade, (SELECT COUNT(*) FROM review_like rl WHERE rl.review_id = r.review_id) AS likeCount, (SELECT COUNT(*) FROM comment c WHERE c.review_id = r.review_id AND c.comment_delete_status != '삭제') AS commentCount FROM review r JOIN member m ON m.member_id = r.member_id
WHERE r.review_platform = '넷플릭스' WHERE r.review_platform = '티빙' WHERE r.review_platform = '디즈니+' WHERE r.review_platform = '기타' WHERE r.review_platform = #{platform}
ORDER BY likeCount DESC, r.review_rating DESC, r.review_created_at DESC LIMIT #{limit}
